import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import SkillTag from '../components/SkillTag';

export default function Students() {
  const { API } = useAuth();
  const [students, setStudents] = useState([]);
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const { data } = await axios.get(`${API}/users/students`);
        setStudents(data);
      } catch {}
      setLoading(false);
    };
    load();
  }, [API]);

  const filtered = students.filter(s =>
    s.name.toLowerCase().includes(search.toLowerCase()) ||
    s.department?.toLowerCase().includes(search.toLowerCase()) ||
    s.skills?.some(sk => sk.toLowerCase().includes(search.toLowerCase()))
  );

  if (loading) return <div style={{padding:'3rem',textAlign:'center',color:'#6c63ff'}}>Loading...</div>;

  return (
    <div style={{padding:'2rem',maxWidth:1200,margin:'0 auto'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1.5rem'}}>
        <h1 style={{fontWeight:800,fontSize:'1.75rem'}}>Students</h1>
        <span style={{color:'#9aa3bf',fontSize:'0.875rem'}}>{filtered.length} students</span>
      </div>

      <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍  Search by name, department, or skill..." style={{width:'100%',padding:'12px 16px',background:'#161c2e',border:'1px solid #252d47',borderRadius:12,color:'#e8eaf0',fontSize:'0.9rem',outline:'none',marginBottom:'2rem'}} />

      <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill, minmax(280px, 1fr))',gap:'1.25rem'}}>
        {filtered.map(s => {
          const initials = s.name.split(' ').map(n=>n[0]).join('').toUpperCase().slice(0,2);
          const colors = ['#6c63ff','#ff6b9d','#00d4aa','#ffb347','#4ade80'];
          const color = colors[s.name.charCodeAt(0) % colors.length];
          return (
            <div key={s._id} style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:16,padding:'1.5rem',textAlign:'center'}}>
              <div style={{width:64,height:64,borderRadius:'50%',background:`linear-gradient(135deg, ${color}80, ${color})`,display:'flex',alignItems:'center',justifyContent:'center',margin:'0 auto 1rem',color:'#fff',fontWeight:800,fontSize:'1.2rem'}}>{initials}</div>
              <h3 style={{fontWeight:700,fontSize:'1rem',marginBottom:'0.25rem'}}>{s.name}</h3>
              <div style={{color:'#6c63ff',fontSize:'0.8rem',fontWeight:600,marginBottom:'0.25rem'}}>{s.year}</div>
              <div style={{color:'#9aa3bf',fontSize:'0.8rem',marginBottom:'1rem'}}>{s.department}</div>
              {s.gpa && <div style={{fontFamily:'Space Mono',fontSize:'0.8rem',color:'#00d4aa',marginBottom:'0.75rem'}}>GPA: {s.gpa}</div>}
              <div style={{display:'flex',gap:'0.4rem',flexWrap:'wrap',justifyContent:'center',marginBottom:'0.75rem'}}>
                {s.skills?.slice(0,4).map(skill => <SkillTag key={skill} skill={skill} />)}
              </div>
              <div style={{display:'flex',gap:'0.5rem',justifyContent:'center'}}>
                {s.github && <a href={s.github} target="_blank" rel="noreferrer" style={{padding:'5px 14px',borderRadius:8,border:'1px solid #252d47',color:'#9aa3bf',fontSize:'0.75rem',textDecoration:'none'}}>GitHub</a>}
                {s.portfolio && <a href={s.portfolio} target="_blank" rel="noreferrer" style={{padding:'5px 14px',borderRadius:8,border:'1px solid #252d47',color:'#9aa3bf',fontSize:'0.75rem',textDecoration:'none'}}>Portfolio</a>}
              </div>
              {s.bio && <p style={{color:'#9aa3bf',fontSize:'0.8rem',marginTop:'0.75rem',fontStyle:'italic',borderTop:'1px solid #1c2340',paddingTop:'0.75rem'}}>"{s.bio?.substring(0,100)}..."</p>}
            </div>
          );
        })}
      </div>
    </div>
  );
}
